Method.Source:
public static void main(Args _args)
{
    AgreementLine agreementLine;
    ETG_AgreementLineQualityGrp agreementLineQualityGrp;
    str con;

    ttsbegin;
    while select forupdate agreementLine where agreementLine.ItemDataAreaId == "O001"
    {
        con = "";

        while select * from agreementLineQualityGrp
                where agreementLineQualityGrp.AgreementLine == agreementLine.RecId
            && agreementLineQualityGrp.DataAreaId == agreementLine.ItemDataAreaId
        {

            con += agreementLineQualityGrp.groupDescription() + " - " + agreementLineQualityGrp.Value +"\n";

        }
        agreementLine.ETG_QualitySpecification = con;
        agreementLine.update();
    }
    ttscommit;

}
